    49→async function chat(message, options = {}) {
    50→  // Handle both string messages and arrays of message objects
    51→  let messages;
    52→  if (Array.isArray(message)) {
    53→    // Filter out system messages and extract them
    54→    const systemMessages = message.filter(m => m.role === 'system');
    55→    const nonSystemMessages = message.filter(m => m.role !== 'system');
    56→
    57→    // Use the first system message content as the system prompt if not already set
    58→    if (systemMessages.length > 0 && !options.system) {
    59→      options.system = systemMessages[0].content;
    60→    }
    61→
    62→    // Ensure messages have proper format (content must be string or array)
    63→    messages = nonSystemMessages.map(m => ({
    64→      role: m.role,
    65→      content: typeof m.content === 'string' ? m.content : String(m.content)
    66→    }));
    67→  } else {
    68→    // Simple string message
    69→    messages = [{ role: 'user', content: String(message) }];
    70→  }
    71→
    72→  // Ensure we have at least one message
    73→  if (messages.length === 0) {
    74→    messages = [{ role: 'user', content: 'Hello' }];
    75→  }
    76→
    77→  const response = await anthropic.messages.create({
    78→    max_tokens: options.maxTokens || options.max_tokens || 8192,
    79→    messages: messages,
    80→    system: options.system,
    81→  }, {
    82→    headers: options.subscriptionId ? { 'X-Subscription-ID': options.subscriptionId } : {}
    83→  });
    84→  return response.content[0].text;
    85→}
